INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Spec-driven documentation$q$, $q$Generates reference docs directly from OpenAPI, AsyncAPI, and Arazzo specification files, keeping docs in sync with the actual API contract.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Automatic changelog & breaking-change detection$q$, $q$Diffs each new spec version against the previous one and publishes a changelog that flags breaking changes automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$API Explorer$q$, $q$An in-documentation console with OAuth auto-fill lets developers send live requests against the API without leaving the docs page.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$CI/CD and CLI integration$q$, $q$A CLI and native GitHub/GitLab integrations let teams publish documentation updates as part of their existing deployment pipeline.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$API Hubs$q$, $q$Publishes a single catalog page that groups multiple related API documentation sites for larger API portfolios.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$MCP tooling for AI agents$q$, $q$Exposes API documentation through Model Context Protocol servers so AI coding assistants can query API references directly.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Branch management & rollback$q$, $q$Pro and higher plans support documentation branches, previews, and one-click rollback to a prior release.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Documentation stays automatically in sync with the OpenAPI/AsyncAPI source of truth$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Automated breaking-change detection reduces surprises for API consumers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$In-doc API Explorer lets users test endpoints without external tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Free Pro-tier access available for verified open-source projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$No permanently free public plan for commercial use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Pricing per API doc/user can add up for teams with many services$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Smaller ecosystem and market presence than larger competitors like Redocly or ReadMe$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Enterprise features (SSO, on-prem MCP dataplane) require custom sales pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$What is Bump.sh used for?$q$, $q$Bump.sh turns OpenAPI, AsyncAPI, and Arazzo specification files into hosted, interactive API reference documentation that updates automatically whenever the underlying spec changes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Does Bump.sh have a free plan?$q$, $q$There is no permanently free public plan, but verified open-source projects can apply for free access to the Pro plan, and paid plans start at $50/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Does Bump.sh support breaking-change detection?$q$, $q$Yes. Bump.sh automatically diffs each new API spec version against the previous one and generates a changelog that highlights breaking changes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Can Bump.sh integrate with CI/CD pipelines?$q$, $q$Yes, Bump.sh offers a CLI and native GitHub/GitLab integrations so documentation deploys automatically as part of existing build pipelines.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Who founded Bump.sh?$q$, $q$Bump.sh was founded in 2020 by CEO Sebastien Charrier in Angers, France.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Public API reference documentation$q$, $q$Teams publishing a public or partner-facing API use Bump.sh to keep reference docs automatically synced with the live API spec.$q$, $q$API-first product and platform teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Multi-API developer portals$q$, $q$Organizations with several microservices or APIs use Hubs to present a unified documentation catalog to internal and external developers.$q$, $q$Platform engineering and DevRel teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$AI-agent-readable API references$q$, $q$Companies exposing MCP endpoints let AI coding assistants query API documentation programmatically rather than scraping HTML docs.$q$, $q$Engineering teams building AI-agent integrations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Basic$q$, $q$$50$q$, $q$per month$q$, NULL, $q$["10 API docs","5 MCP tools","3 internal users","20 guest users","OpenAPI/AsyncAPI/Arazzo support","CLI and GitHub integration","Custom domain and logo"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Pro$q$, $q$$250$q$, $q$per month (14-day free trial)$q$, NULL, $q$["30 API docs","50 MCP tools","5 internal users","40 guest users","API Explorer","Private MCP servers","Branch management","Full CI integration","Release rollback","Automatic changelog"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$Custom$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Unlimited internal/external users","SSO","Reverse proxy & embed mode","On-premise MCP dataplane","Custom reports","99.99% SLA"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bump.sh is a docs-as-code API documentation platform that renders OpenAPI, AsyncAPI, and Arazzo specification files into hosted, interactive reference sites. Instead of manually writing and updating API documentation, teams commit their spec files and let Bump.sh regenerate the docs automatically whenever the spec changes.$q$, $q$The company was founded in 2020 by CEO Sebastien Charrier in Angers, France, after he experienced the pain of maintaining hand-written API docs while rewriting a payment API at a previous company. Bump.sh operates as a small, fully remote team based in France.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include server-side rendering built to handle very large OpenAPI files, an automated changelog that flags breaking changes between spec versions, an in-doc API Explorer with OAuth auto-fill for testing endpoints directly from the documentation, and Hubs for publishing a catalog of multiple related APIs under one portal.$q$, $q$Bump.sh also supports CLI and Git-based CI/CD integration (GitHub, GitLab) so documentation updates ship as part of the normal deployment pipeline, plus branch previews, release rollback, and Slack notifications on higher-tier plans. More recently the company added MCP (Model Context Protocol) tooling so AI coding agents can query API references programmatically.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bump.sh has no permanently free public tier; pricing starts at $50/month for the Basic plan (10 API docs, 3 internal users, 20 guests). The Pro plan is $250/month with a 14-day free trial and adds the API Explorer, private MCP servers, and full CI integration. An Enterprise/Custom plan adds SSO, an SLA, and unlimited users at custom pricing.$q$, $q$Verified open-source projects can apply for free access to the Pro plan, which is a notable exception to the otherwise fully paid pricing model.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a078e17b-44db-40a3-bdc1-7247b3634fc8', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Intercepting proxy$q$, $q$Captures and lets testers inspect or modify HTTP/S and WebSocket traffic passing between the browser and target application.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Automated vulnerability scanner$q$, $q$Crawls application content and actively audits it for vulnerability classes such as SQL injection and XSS (Professional and Enterprise editions).$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Repeater$q$, $q$Lets testers manually resend and modify individual requests repeatedly to probe for input-based vulnerabilities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Intruder$q$, $q$Automates customized attacks by inserting payloads into defined positions across repeated requests, useful for fuzzing and brute-force testing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$BApp Store$q$, $q$A marketplace of community-built extensions that add functionality on top of the core Burp toolset.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Sequencer, Decoder, Comparer$q$, $q$Utility tools for analyzing session token randomness, decoding/encoding data, and diffing two pieces of data or requests.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Burp Suite DAST (Enterprise)$q$, $q$A CI/CD-integrated, Docker-deployable dynamic scanning product for scheduled, team-managed scanning across many applications.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Industry-standard toolkit taught extensively in penetration testing and bug bounty training$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Free Community Edition provides real manual testing capability, not just a crippled demo$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Deep manual testing controls (Repeater, Intruder) alongside automated scanning$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Extensible via the BApp Store for custom or niche testing needs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Full scanning capability requires the paid Professional license$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Enterprise/DAST pricing is not public and requires a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Steeper learning curve for testers unfamiliar with manual proxy-based workflows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Community Edition throttles Intruder speed, limiting large-scale automated testing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Is Burp Suite free?$q$, $q$Burp Suite Community Edition is free and includes the core manual testing toolkit, but it lacks the automated vulnerability scanner found in Professional and Enterprise editions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$How much does Burp Suite Professional cost?$q$, $q$Burp Suite Professional is priced at $475 per user per year.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$What is the difference between Burp Suite Professional and Enterprise?$q$, $q$Professional is a desktop application for manual and semi-automated testing by an individual tester. Enterprise (Burp Suite DAST) is a team-oriented, CI/CD-integrated scanning platform for scheduled scans across many applications.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$What operating systems does Burp Suite run on?$q$, $q$Burp Suite is a Java-based desktop application that runs on Windows, macOS, and Linux.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Who makes Burp Suite?$q$, $q$Burp Suite is developed by PortSwigger, a UK company founded in 2008 by Dafydd Stuttard and headquartered in Knutsford, Cheshire.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Manual web application penetration testing$q$, $q$Security consultants use Burp's proxy, Repeater, and Intruder to manually probe applications for logic flaws and input-based vulnerabilities.$q$, $q$Penetration testers and security consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Automated vulnerability scanning in CI/CD$q$, $q$AppSec teams deploy Burp Suite DAST in build pipelines to catch vulnerabilities before deployment across many applications on a schedule.$q$, $q$Application security engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Bug bounty hunting$q$, $q$Independent researchers use Burp Suite Professional's scanner and manual tools to find and report vulnerabilities in bug bounty programs.$q$, $q$Independent security researchers and bug bounty hunters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Intercepting proxy","Repeater","Throttled Intruder","Decoder, Comparer, Sequencer","Manual testing tools only, no automated scanner"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Professional$q$, $q$$475/user$q$, $q$per year$q$, NULL, $q$["Full automated Scanner","Unthrottled Intruder","BApp Store extensions","Burp AI features","All manual testing tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$Enterprise (Burp Suite DAST)$q$, $q$Custom$q$, $q$annual, contact sales$q$, NULL, $q$["CI/CD-integrated scanning","Scheduled scans","Team management","Docker-based deployment","Centralized reporting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Burp Suite is a web application security testing toolkit developed by PortSwigger, founded in 2008 by Dafydd Stuttard and based in Knutsford, UK. It combines an intercepting proxy, automated vulnerability scanner, and a set of manual testing tools used by penetration testers, bug bounty hunters, and application security teams worldwide.$q$, $q$PortSwigger has grown from Stuttard's solo project into one of the leading vendors in web application security testing, with Burp Suite reportedly used by more than 80,000 individuals and over 1,000 enterprise customers, and the company received a $112 million growth investment in 2024.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Burp Suite's toolset centers on an intercepting proxy that lets testers view and modify traffic between browser and server, Repeater for manually resending and tweaking individual requests, and Intruder for automating customized attacks such as parameter fuzzing. Professional and Enterprise editions add an automated Scanner that crawls applications and audits for common vulnerability classes.$q$, $q$Additional utilities include Decoder and Comparer for data encoding and diffing tasks, Sequencer for analyzing the randomness of session tokens, and the BApp Store, a marketplace of community-built extensions that expand Burp's functionality.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Burp Suite Community Edition is free but excludes the automated scanner and throttles Intruder speed. Burp Suite Professional costs $475 per user per year and unlocks the full scanner, unthrottled Intruder, BApp Store access, and Burp AI features.$q$, $q$Burp Suite Enterprise (marketed as Burp Suite DAST) is a separate CI/CD scanning product for teams, priced on request; real-world enterprise deals are commonly reported in the tens of thousands of dollars annually depending on scan frequency and support requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('753226c3-cede-4bbb-9fad-9d73dd9827e4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Remixable template library$q$, $q$A library of pre-built video templates from real brands that teams can duplicate and customize instead of starting from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Modular block-based editor$q$, $q$A component-based design system lets teams build and reuse branded elements across multiple videos and campaigns.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$AI background removal$q$, $q$Automatically removes backgrounds from product and model footage without manual rotoscoping.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$AI auto-captioning$q$, $q$Generates and styles video captions automatically, with a set number of captioning minutes included per plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Magic resize$q$, $q$Automatically reformats a single video into the aspect ratios needed for different social platforms.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Motion graphics tools$q$, $q$Provides animation and compositing capability aimed at teams who want After Effects-style output without the learning curve.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Team template libraries$q$, $q$Teams can save custom templates and building blocks so anyone on the team can produce on-brand video content.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Template-first workflow speeds up video production for non-specialist marketers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$AI captioning and background removal cut out manual, time-consuming editing steps$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Free plan available to try the core editor before paying$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Used by well-known consumer brands, suggesting production-grade output quality$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Full pricing tiers and feature-by-plan breakdown are not fully published$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Small team size relative to larger video editing platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Name collision with an unrelated Danish company also called Butter can cause research confusion$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Positioned mainly for marketing/social video, not general-purpose film or long-form editing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$What is Butter used for?$q$, $q$Butter is a video creative suite used by marketing and e-commerce teams to produce branded social videos, ads, and motion graphics quickly using templates and reusable design blocks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Is Butter free?$q$, $q$Butter offers a free plan for individual use; paid Pro plans are reported to start around $18 per month, though the company has not published a full public pricing grid.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Does Butter use AI?$q$, $q$Yes. Butter includes AI-powered background removal, automatic video captioning, and automatic aspect-ratio resizing (magic resize).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Is Butter the same company as the Butter virtual workshop tool?$q$, $q$No. The video creative suite (usebutter.com) is led by CEO Nate Yu and based in Los Angeles, while the separate virtual workshop/meeting platform also called Butter was founded in Denmark by a different founding team; the two share a name but are distinct companies.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Who is Butter for?$q$, $q$Butter is primarily aimed at DTC and e-commerce brands and marketing teams that need to produce a high volume of short-form video content for social and paid media.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Social ad production at scale$q$, $q$Marketing teams use Butter's templates and magic resize to quickly produce multiple ad variants across social platforms.$q$, $q$DTC and e-commerce marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Branded template libraries$q$, $q$Creative teams build a reusable library of on-brand templates and components so any team member can ship consistent video content.$q$, $q$In-house brand and creative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$Product video creation$q$, $q$Teams use AI background removal and motion graphics tools to turn raw product and lifestyle footage into polished marketing videos.$q$, $q$E-commerce product marketers$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Butter is a video creative suite built for marketing and e-commerce teams that need to produce a high volume of branded video content - social ads, product videos, motion graphics - without a full video production team. Founded in 2020 and based in Los Angeles, the company is led by CEO Nate Yu and operates as a small, lean team.$q$, $q$Rather than starting from a blank editing timeline, Butter is built around remixable templates and reusable design blocks, so marketers can produce on-brand videos quickly and non-designers can still ship polished output. The company lists brands including Disney, SpaceX, DoorDash, Sony Music, and Lyft among its customers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Butter's core workflow combines a growing template library with a modular, block-based design system, letting teams save their own branded templates and components for reuse across campaigns. Its motion graphics tools aim to offer After-Effects-style animation with a gentler learning curve.$q$, $q$AI-assisted features include automatic background removal for product and talent footage, one-click AI captioning with customizable styling, and automatic resizing of a single video into multiple social media aspect ratios.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Butter offers a free plan for individual use, with paid Pro plans reported by third-party sources to start around $18 per month; paid tiers include a fixed allotment of AI auto-captioning minutes and export options. Butter does not publish a detailed public pricing grid, and a 7-day money-back guarantee applies to paid subscriptions.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d85d55fa-0d1c-4513-9dd7-5d0afd3835fd', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Visual editor with live preview$q$, $q$Marketers can edit content in a WYSIWYG interface and preview exactly how it will render before publishing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Content API for any framework$q$, $q$A REST-style API delivers content into React, Next.js, Vue, Rails, Django, and other front-end or back-end stacks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$AI Assistant$q$, $q$Built-in AI tooling helps content teams draft, edit, and optimize content within the CMS.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$SEO metadata fields$q$, $q$Native fields for titles, descriptions, and other metadata help content teams manage on-page SEO without developer involvement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Multi-locale content$q$, $q$Higher-tier plans support managing content in multiple languages/locales from a single workspace.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Roles and permissions$q$, $q$Role-based access control lets teams restrict who can edit or publish specific content types.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Webhooks and write API$q$, $q$Optional add-ons on Advanced and Professional plans let external systems trigger updates or push content into ButterCMS programmatically.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$API-first design lets marketers publish without waiting on developer deploys$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Works with virtually any front-end framework via a content API$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Free Developer plan available for testing and small non-commercial projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Built-in AI Assistant and live preview speed up content workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Paid plans get expensive quickly for teams needing higher API call or bandwidth limits$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Multi-locale support is limited to higher-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Enterprise pricing is not publicly listed and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Fewer front-end starter integrations than some larger headless CMS competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$What is ButterCMS?$q$, $q$ButterCMS is a headless content management system that lets marketing teams manage content through a dashboard while developers integrate it into any front-end via an API.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Does ButterCMS have a free plan?$q$, $q$Yes, ButterCMS offers a free Developer plan intended for personal, non-commercial projects, with paid plans starting at $71/month for commercial use.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Who owns ButterCMS?$q$, $q$ButterCMS was founded in 2014 by Abi Noda and Jake Lumetta and was acquired by Tiugo Technologies in December 2022.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$What frameworks does ButterCMS work with?$q$, $q$ButterCMS provides a content API that integrates with React, Next.js, Vue, Ruby on Rails, Django, and most other front-end or back-end frameworks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Does ButterCMS support multiple languages?$q$, $q$Multi-locale content management is available starting on the Professional plan, which includes support for 3 locales.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Marketing blog and content management$q$, $q$SaaS marketing teams use ButterCMS to publish and update a company blog without needing a developer for every post.$q$, $q$Marketing and content teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Multi-site content delivery$q$, $q$Engineering teams pull the same content into multiple front-end properties (web app, marketing site, mobile app) via the shared content API.$q$, $q$Product and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Localized marketing pages$q$, $q$Global companies use multi-locale support to manage translated marketing pages from a single ButterCMS workspace.$q$, $q$International marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Free (Developer)$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["50K API calls/month","100GB bandwidth","5 pages","50 blog posts","50 collections","500 assets","2 roles","Non-commercial use only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Basic$q$, $q$$71$q$, $q$per month (10% off annually)$q$, NULL, $q$["100K API calls/month","250GB bandwidth","20 pages","100 blog posts","100 collections","1K assets","Image editing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Advanced$q$, $q$$224$q$, $q$per month$q$, NULL, $q$["500K API calls/month","500GB bandwidth","50 pages","500 blog posts","500 collections","2K assets","Optional write API, webhooks, video uploads"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Professional$q$, $q$$359$q$, $q$per month$q$, NULL, $q$["1M API calls/month","1TB bandwidth","100 pages","Unlimited blog posts","1K collections","3 locales","Optional multi-environment add-on"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$Enterprise + Agency$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Custom API calls, bandwidth, pages, collections","Custom locales","Dedicated customer success manager","SLA","Implementation support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ButterCMS is a headless content management system founded in 2014 in San Francisco by Abi Noda and Jake Lumetta, and acquired by Tiugo Technologies in December 2022. It separates content authoring from the presentation layer, letting marketers publish through a hosted dashboard while developers pull content into any framework via an API.$q$, $q$The product is aimed primarily at marketing and content teams at SaaS companies who want to manage blogs, marketing pages, and knowledge bases without depending on a developer for every content update, while still giving engineering full control over how content is rendered.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ButterCMS includes a visual page builder with live preview, SEO metadata fields, role-based permissions, and a content API that works with React, Next.js, Vue, Rails, Django, and other frameworks. Higher tiers add multi-locale content, a write API, webhooks, and multi-environment support for staging versus production content.$q$, $q$The platform also includes an AI Assistant to help teams draft and edit content faster, and every plan - including the free Developer tier - supports unlimited users and reusable content components.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ButterCMS offers a free Developer plan for non-commercial projects, then four paid tiers: Basic ($71/month), Advanced ($224/month), Professional ($359/month), and a custom-priced Enterprise/Agency tier. All paid plans include a 14-day free trial and roughly 10% savings on annual billing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
