INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b333f512-f7fd-4bd3-a4a4-6210ddaae0a8', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Automatic directory distribution$q$, $q$Submits the podcast RSS feed automatically to Apple Podcasts, Spotify, Amazon Music, and other major directories.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Advanced analytics$q$, $q$Provides detailed download and listener data, including geographic and platform breakdowns, beyond basic download counts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$AI-generated transcripts$q$, $q$Automatically transcribes episodes, improving accessibility and giving podcasters repurposable text content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Podcast website and players$q$, $q$Includes a customizable podcast website plus embeddable and social-media-optimized episode players.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Monetization tools$q$, $q$Offers an ad network marketplace and listener support/subscription options to help podcasters generate revenue.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Video podcast publishing$q$, $q$The Audio + Video plan lets creators publish video episodes directly to Apple Podcasts at up to 1080p resolution.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Team collaboration$q$, $q$Supports multiple team members and co-hosts working on the same show from one account.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Simple setup with automatic submission to all major podcast directories$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Free plan available to try the platform before paying$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Built-in AI transcripts and analytics without needing third-party tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Video podcast publishing supported alongside traditional audio hosting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Free plan limits uploads to 2 hours/month with only 90-day episode retention$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Pricing is based on upload hours, which can be confusing compared to flat unlimited-storage competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Advanced monetization features depend on meeting ad network eligibility requirements$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Higher-tier plans required for shows publishing many hours of content per month$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Is Buzzsprout free?$q$, $q$Buzzsprout has a free plan that allows 2 hours of uploads per month, with episodes hosted for 90 days; paid plans start at $15/month for more upload hours and permanent hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Does Buzzsprout submit my podcast to Apple Podcasts and Spotify?$q$, $q$Yes, Buzzsprout automatically submits your podcast's RSS feed to major directories including Apple Podcasts, Spotify, and Amazon Music.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Does Buzzsprout offer transcripts?$q$, $q$Yes, Buzzsprout automatically generates AI transcripts for episodes on paid plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Can I publish video podcasts on Buzzsprout?$q$, $q$Yes, the Audio + Video plan lets you publish video episodes directly to Apple Podcasts at resolutions up to 1080p.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$How is Buzzsprout pricing structured?$q$, $q$Buzzsprout charges based on monthly or annual upload hours rather than total storage, with plans ranging from a free 2-hour/month tier up to a Multi-Podcast plan covering multiple shows.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Independent podcast hosting$q$, $q$Solo podcasters use Buzzsprout to host episodes, generate an RSS feed, and get automatically listed on major directories.$q$, $q$Independent podcasters and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Podcast networks with multiple shows$q$, $q$Networks use the Multi-Podcast plan to host 5-10 shows under one account with a shared pool of upload hours.$q$, $q$Podcast networks and media companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Branded business podcasts$q$, $q$Companies use Buzzsprout's analytics and monetization tools to run a podcast as part of a content marketing strategy.$q$, $q$Marketing teams and brand podcasters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["2 hours of uploads/month","90-day episode hosting","Basic podcast hosting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Audio$q$, $q$$15$q$, $q$per month, billed annually$q$, NULL, $q$["72 upload hours/year","1 podcast","Directory listing","Advanced stats","Premium website"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Audio + Video$q$, $q$$25$q$, $q$per month, billed annually$q$, NULL, $q$["72 upload hours/year","1 podcast","Video publishing to Apple Podcasts up to 1080p"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Multi-Podcast$q$, $q$$30$q$, $q$per month, billed annually$q$, NULL, $q$["180 upload hours/year","5-10 podcasts depending on media type","Shared upload hours across shows"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$Archive$q$, $q$$5$q$, $q$per month$q$, NULL, $q$["Keeps podcast live without new uploads"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Buzzsprout is a podcast hosting platform founded in 2009 by Tom Rossi and Kevin Finn, headquartered in Jacksonville, Florida. It handles the technical side of running a podcast - media hosting, RSS feed generation, and directory submission - so creators can focus on producing episodes rather than infrastructure.$q$, $q$The company has grown to roughly 53 employees and thousands of paying podcaster customers, and is commonly recommended to new podcasters for its straightforward setup process and built-in directory distribution to platforms like Apple Podcasts and Spotify.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include automatic submission to major podcast directories, advanced download and audience analytics, AI-generated episode transcripts, a customizable podcast website, and embeddable episode players for social sharing.$q$, $q$Buzzsprout also offers monetization tools through an ad marketplace and listener support/subscriptions, team collaboration for multi-host shows, and an Audio + Video plan that publishes video episodes to Apple Podcasts at up to 1080p.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Buzzsprout prices plans around monthly/annual upload hours rather than storage. The free plan allows 2 hours of uploads per month with 90-day hosting; paid plans start at $15/month (billed annually) for the Audio plan, scaling up to $25/month for Audio + Video and $30/month for the Multi-Podcast plan covering up to 10 shows. A $5/month Archive plan preserves an inactive show without new uploads.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('087b8581-02ae-4bfb-bac4-4d3ce7f324de', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$GitOps database-as-code workflow$q$, $q$Integrates natively with GitHub and GitLab so schema changes go through the same review and merge process as application code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Automated schema migration with rollback$q$, $q$Applies database schema changes automatically and supports rolling back a change if something goes wrong.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$SQL review with 200+ lint rules$q$, $q$Enforces SQL style and safety standards automatically before changes are applied.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Broad database engine support$q$, $q$Works across PostgreSQL, MySQL, MariaDB, TiDB, Snowflake, ClickHouse, MongoDB, Redis, Oracle, SQL Server, and Spanner.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Dynamic data masking$q$, $q$Masks sensitive column-level data for users without appropriate access, available on Enterprise.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Role-based access control$q$, $q$Provides fine-grained permissions at the project and workspace level for teams and DBAs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Self-hosted or cloud deployment$q$, $q$Can run fully self-hosted for free at the Community tier or as a managed cloud service on paid plans.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Free, self-hostable Community edition with real database change management functionality$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Open-source codebase avoids vendor lock-in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Wide database engine support in a single tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Built by former Google Cloud SQL engineers with deep database infrastructure experience$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Community edition caps users (20) and database instances (10)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Enterprise pricing is not publicly listed and requires an annual contract$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Small company/team size relative to established database tooling vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Some advanced governance features (masking, custom approval) reserved for paid tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Is Bytebase open source?$q$, $q$Yes, Bytebase is open source and available on GitHub, with a free, self-hostable Community edition.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$What databases does Bytebase support?$q$, $q$Bytebase supports PostgreSQL, MySQL, MariaDB, TiDB, Snowflake, ClickHouse, MongoDB, Redis, Oracle, SQL Server, Spanner, and more.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$How much does Bytebase Pro cost?$q$, $q$The Pro plan is $20 per user per month and can be self-hosted or used as a managed cloud service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Who founded Bytebase?$q$, $q$Bytebase was founded in 2021 by Tianzhou Chen and Danny Xu, former technical leads on Google Cloud SQL, and is headquartered in Mountain View, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Does Bytebase support GitOps workflows?$q$, $q$Yes, Bytebase integrates natively with GitHub and GitLab so database schema changes can be reviewed and merged like application code.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Database schema change management$q$, $q$Engineering teams use Bytebase to review, approve, and apply schema migrations safely with rollback support.$q$, $q$Backend engineering and DBA teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$SQL review and governance$q$, $q$Platform teams enforce SQL lint rules and approval workflows before changes reach production databases.$q$, $q$Platform engineering and database administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Compliance-sensitive data access$q$, $q$Organizations use dynamic data masking and RBAC to restrict sensitive data access across regulated environments.$q$, $q$Enterprises in finance, healthcare, and regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Community$q$, $q$Free$q$, $q$forever, self-hosted$q$, NULL, $q$["Up to 20 users","10 database instances","Community support","Core database change management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Pro$q$, $q$$20/user$q$, $q$per month$q$, NULL, $q$["Unlimited users","10 database instances","Google/GitHub SSO","User and database groups","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$Enterprise$q$, $q$Custom$q$, $q$annual, contact sales$q$, NULL, $q$["Unlimited users and instances","OIDC/LDAP/SCIM/2FA","Dynamic data masking","Custom approval workflows","Unlimited audit log retention","SLA-backed support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bytebase is an open-source database DevOps platform founded in 2021 by Tianzhou Chen and Danny Xu, former Google Cloud SQL engineers, and headquartered in Mountain View, California. It manages the database schema and data change lifecycle - migrations, SQL review, version control, and rollback - across a wide range of database engines.$q$, $q$The project is open source on GitHub and listed in the CNCF landscape, and it can be fully self-hosted for free at the Community tier, making it a common choice for engineering and platform teams that want database change governance without vendor lock-in.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bytebase provides GitOps-style database-as-code workflows via native GitHub/GitLab integration, automated schema migrations with rollback, and more than 200 configurable SQL lint rules for review standards. It supports PostgreSQL, MySQL, MariaDB, TiDB, Snowflake, ClickHouse, MongoDB, Redis, Oracle, SQL Server, and Spanner.$q$, $q$Enterprise-focused capabilities include column-level dynamic data masking, fine-grained role-based access control, advanced authentication (OIDC, LDAP, SCIM, 2FA), and audit logging for compliance-sensitive environments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community edition is free forever, self-hosted, and supports up to 20 users and 10 database instances. The Pro plan is $20 per user per month and removes the user cap while adding SSO and group management. Enterprise pricing is custom and billed annually, adding advanced compliance and support features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Cookieless visitor tracking$q$, $q$Estimates unique visitors without cookies, IP address storage, or browser fingerprinting, avoiding the need for a cookie consent banner.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$EU-based, encrypted data processing$q$, $q$All analytics data is processed and stored exclusively in the EU and described as end-to-end encrypted.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Carbon emissions reporting$q$, $q$Estimates the CO2 footprint generated by a website's traffic and flags oversized page assets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Lightweight tracking script$q$, $q$The tracking script is reported to be roughly 77 times smaller than Google Analytics, reducing page load overhead.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Custom events and UTM tracking$q$, $q$Supports tracking custom user actions and campaign attribution via UTM parameters.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Public analytics API$q$, $q$Provides an API for pulling analytics data programmatically into other tools or dashboards.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Weekly email reports$q$, $q$Sends automated weekly summaries of site traffic to site owners.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$No cookie consent banner needed due to cookieless, non-identifying tracking design$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$GDPR, CCPA, ePrivacy, and PECR compliant by design with EU-only data storage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Very lightweight script compared to Google Analytics$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Unique carbon footprint reporting not found in most analytics tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Free plan limited to a single website with 30-day data retention$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Run as a solo/independent project, which may raise longevity or support-capacity questions for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Feature set is more basic than full-featured analytics suites like GA4 or Plausible$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Pro plan's 'unlimited' page views are subject to an undefined fair-use policy$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Is Cabin free to use?$q$, $q$Yes, Cabin has a free Basic plan for one website with 30-day data retention; the Pro plan is $19/month for unlimited websites and unlimited data retention.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Does Cabin use cookies?$q$, $q$No, Cabin does not use cookies, store visitor IP addresses, or perform browser fingerprinting, which generally removes the need for a cookie consent banner.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Is Cabin GDPR compliant?$q$, $q$Yes, Cabin is designed to be GDPR, CCPA, ePrivacy, and PECR compliant by default, with data processed and stored exclusively in the EU.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Who runs Cabin?$q$, $q$Cabin was created by developer Nic Mulvaney, originally incubated at the design studio Normally around 2020, and has been fully independent since Normally closed in January 2025.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Does Cabin track carbon emissions?$q$, $q$Yes, Cabin includes a feature that estimates a website's CO2 footprint from its traffic and highlights large assets contributing to it.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Cookie-banner-free analytics$q$, $q$Site owners who want to avoid displaying a cookie consent banner use Cabin's non-identifying tracking method.$q$, $q$Privacy-conscious website owners and indie developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$GDPR-compliant EU analytics$q$, $q$Businesses serving EU visitors use Cabin's EU-only data storage and compliance-by-design approach to simplify privacy compliance.$q$, $q$Small businesses and startups serving EU users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Sustainability-focused reporting$q$, $q$Teams tracking their website's environmental impact use Cabin's carbon emissions reporting alongside standard traffic metrics.$q$, $q$Sustainability-minded companies and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 website","30-day data retention","Unlimited page views","Data export","CO2 reporting","Custom events","Weekly email reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$Pro$q$, $q$$19$q$, $q$per month$q$, NULL, $q$["Unlimited websites","Unlimited data retention","Unlimited page views (fair use)","Data export","CO2 reporting","Custom events","Weekly email reports"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cabin is a privacy-first, cookieless web analytics tool created by developer Nic Mulvaney, originally incubated at the design studio Normally starting around 2020 and now run independently since Normally closed in January 2025. It positions itself as a lightweight, ethical alternative to Google Analytics.$q$, $q$Rather than using cookies, IP address storage, or browser fingerprinting to identify visitors, Cabin uses a method that estimates unique visits without storing any personal identifiers, which the company says makes sites using it compliant with GDPR, CCPA, ePrivacy, and PECR without needing a cookie consent banner.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cabin provides standard analytics - page views, referrers, geographic and device data, custom events, and UTM campaign tracking - through a script reported to be about 77 times smaller than Google Analytics' tracking code. All data processing and storage is described as EU-based and end-to-end encrypted.$q$, $q$A distinctive feature is Cabin's carbon-emissions reporting, which estimates a website's CO2 footprint from traffic over time and flags oversized assets contributing to it. Cabin also offers a public analytics API and weekly email reports.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cabin has two plans: a free Basic plan covering one website with 30-day data retention and unlimited page views, and a $19/month Pro plan that removes the website cap and retention limit for unlimited websites and unlimited data retention (subject to fair use).$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0050715-8a0a-4437-8c80-e7d842301783', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Current month display$q$, $q$Running cal with no arguments prints a calendar for the current month by default.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Arbitrary month/year lookup$q$, $q$Accepts a month and year argument to display the calendar for any specific month in history or the future.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Full-year view$q$, $q$Passing a single year argument prints all twelve months of that year at once.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Configurable week start$q$, $q$Supports flags to start the displayed week on either Sunday or Monday.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Julian date display$q$, $q$Can optionally show day-of-year (Julian) dates alongside standard calendar dates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Historical calendar accuracy$q$, $q$Correctly reflects the September 1752 Julian-to-Gregorian calendar transition on many implementations.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Available by default on virtually every Unix-like system with no installation needed$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Extremely lightweight and fast for quick terminal reference$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Simple, stable command syntax that has changed little in decades$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$No cost, license, or account required$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Output formatting and supported flags vary slightly between implementations (GNU/Linux vs BSD/macOS)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$No graphical interface, reminders, or event/scheduling functionality$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Limited to displaying dates - no integration with calendar apps or scheduling systems$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Less commonly used since GUI and web-based calendar apps became standard for scheduling$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$What does the cal command do?$q$, $q$cal prints a plain-text calendar to the terminal, showing the current month by default or any specified month or year.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Is cal free?$q$, $q$Yes, cal is a free, built-in command-line utility included by default with Unix-like operating systems; there is no cost or license involved.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$How do I show a whole year with cal?$q$, $q$Running cal followed by just a year (e.g. cal 2026) prints all twelve months of that year.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Does cal work the same on macOS and Linux?$q$, $q$The core functionality is the same, but macOS/BSD and Linux (GNU/util-linux) implementations can differ slightly in default formatting and supported flags.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$What is the difference between cal and ncal?$q$, $q$ncal is a related utility, available on most of the same systems, that displays the calendar in an alternate vertical layout compared to cal's default horizontal grid.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Quick terminal date reference$q$, $q$Developers and sysadmins run cal to quickly check a date or day-of-week without leaving the terminal.$q$, $q$Developers and system administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$Scripting and shell automation$q$, $q$Shell scripts parse cal's output or use its date logic as a lightweight way to reference calendar information.$q$, $q$Shell scripters and automation engineers$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$cal is a command-line utility that prints a plain-text calendar to the terminal. It is not a commercial product or company; it is one of the original small utilities from early Unix, written by Doug McIlroy for the first PDP-11 Unix implementation around 1971 and present in Version 6 AT&T UNIX.$q$, $q$Because of that lineage, cal is specified in the Single UNIX Specification and ships by default with virtually every Unix-like operating system, including Linux distributions, macOS, and other BSD systems - there is nothing to install, sign up for, or pay for.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$With no arguments, cal prints the current month; it also accepts a month and year to display an arbitrary month, or a single year to print all twelve months at once. Common flags control whether weeks start on Sunday or Monday and whether Julian (day-of-year) dates are shown.$q$, $q$A frequently cited historical detail is cal's handling of the September 1752 Julian-to-Gregorian calendar switch, when eleven days were dropped from the calendar in Britain and its colonies - many implementations still reproduce this gap when run against that specific month and year.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$cal is free and included by default with the operating system; there is no license, subscription, or paid tier. Related tools like ncal and the more feature-rich GNU gcal are separate, optional utilities on some systems.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb305b30-042c-4afd-9644-7a70d5644c21', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
