-- Enrichment marathon batch: Bump.sh, Burp Suite, Butter, ButterCMS, Buzzsprout, Bytebase, Cabin, cal

-- ── Bump.sh ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bump.sh turns OpenAPI, AsyncAPI, and Arazzo specification files into always up-to-date, interactive API reference documentation and changelogs.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$50/month$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small team (~6-10 employees)$q$, company_size),
  headquarters = COALESCE($q$Angers, France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bump.sh Review 2026: Pricing, Features & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Bump.sh generates interactive API docs from OpenAPI/AsyncAPI specs with automatic changelogs. See pricing, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bump.sh is an API documentation platform, founded in 2020 by CEO Sebastien Charrier and headquartered in Angers, France. The company operates as a small, fully remote, France-based team. Bump.sh converts machine-readable API specification files - OpenAPI, AsyncAPI, and Arazzo - into hosted, always-current reference documentation using a docs-as-code workflow: teams push spec changes via CLI or GitHub/GitLab CI integration and Bump.sh renders an updated documentation portal automatically. Charrier conceived the product while rewriting the payment API at Capitaine Train, where he experienced firsthand how quickly hand-maintained API docs go stale. Distinguishing features include server-side rendering that can handle very large OpenAPI files without breaking, an automated changelog that detects and flags breaking changes between spec versions, an in-browser API Explorer with OAuth auto-fill so developers can test endpoints directly from the docs, and a Hubs feature that lets teams publish a single catalog page listing multiple related APIs. Bump.sh has also added MCP (Model Context Protocol) tooling so AI coding agents can query API documentation directly, positioning the product for both human and AI-agent consumption of API references. Pricing is subscription-based across three tiers. The Basic plan is $50/month and covers 10 API docs, 5 MCP tools, 3 internal users, and 20 guest users, with OpenAPI/AsyncAPI/Arazzo support, CLI and GitHub integration, and a custom domain. The Pro plan is $250/month (with a 14-day free trial) and raises limits to 30 docs, 50 MCP tools, 5 internal users, and 40 guests, adding the API Explorer, private MCP servers, branch management, full CI integration, release rollback, and automatic changelogs. A Custom/Enterprise tier offers unlimited users, SSO, a reverse proxy/embed mode, an on-premise MCP dataplane, custom reporting, and a 99.99% SLA, with pricing set through direct sales conversations. Bump.sh also gives verified open-source projects free access to the Pro plan. The product targets API-first engineering teams, developer relations teams, and platform teams who maintain public or partner-facing APIs and want documentation that cannot drift out of sync with the actual spec. It competes with tools like Redocly, Stoplight, ReadMe, and Swagger UI/Hub in the API documentation and developer portal space. Support is described by the company as full human support available on every plan, including the Basic tier.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a078e17b-44db-40a3-bdc1-7247b3634fc8';

