-- ── Burp Suite ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Burp Suite is PortSwigger's web application security testing toolkit, combining an intercepting proxy, scanner, and manual testing tools for penetration testers.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community); Professional $475/user/year$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$~338 employees (PortSwigger)$q$, company_size),
  headquarters = COALESCE($q$Knutsford, Cheshire, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Burp Suite Review 2026: Pricing, Features & Editions$q$, seo_title),
  seo_meta_description = COALESCE($q$Burp Suite by PortSwigger is a leading web app security testing toolkit. Compare Community, Professional, and Enterprise editions, pricing, and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Burp Suite is a web application security testing toolkit built by PortSwigger, a company founded in 2008 by Dafydd Stuttard and headquartered in Knutsford, Cheshire, in the northwest of England. PortSwigger has grown into a market leader in web security testing tools, employing several hundred people (reported around 338 as of mid-2026) and receiving a $112 million growth investment from Brighton Park Capital in 2024. Burp Suite is used by an estimated 80,000+ individual security professionals and over 1,000 enterprises, including large organizations such as Microsoft, Amazon, and Salesforce, and it underpins much of PortSwigger's free Web Security Academy training content. The product ships in three editions. Burp Suite Community Edition is free and includes the core manual testing toolkit - an intercepting HTTP/WebSocket proxy, Repeater for resending and modifying individual requests, a throttled version of Intruder for automated attacks, and Burp's Decoder, Comparer, and Sequencer utilities - but omits the automated vulnerability scanner and has reduced performance limits. Burp Suite Professional, priced at $475 per user per year, adds the full automated web vulnerability Scanner that crawls and audits applications for issues such as SQL injection and cross-site scripting, unthrottled Intruder for faster automated attacks, access to the BApp Store for community-built extensions, and PortSwigger's newer Burp AI capabilities. Burp Suite Enterprise, marketed as Burp Suite DAST, is a separate CI/CD-oriented dynamic application security testing product designed for team-based, scheduled, and pipeline-integrated scanning; it is Docker-deployable, offers centralized vulnerability management and reporting across many applications, and is sold on a custom-quoted annual basis, with real-world enterprise contracts commonly landing in the tens of thousands of dollars per year depending on scan volume and support tier. Burp Suite is a desktop Java application that runs on Windows, macOS, and Linux. It is the de facto standard tool taught in many penetration testing and bug bounty training programs, and PortSwigger's free Web Security Academy (built around Burp) is widely used to learn web application security concepts such as SSRF, insecure deserialization, and access control vulnerabilities. Typical users are penetration testers, red teams, application security engineers, and bug bounty hunters who need both automated scanning and fine-grained manual request manipulation in one toolkit.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '753226c3-cede-4bbb-9fad-9d73dd9827e4';

