-- ── Butter ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Butter is an AI-native video creative suite that lets marketing teams build branded motion graphics, ads, and social videos from reusable templates.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro plans reportedly from ~$18/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small team (~10-15 employees)$q$, company_size),
  headquarters = COALESCE($q$Los Angeles, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Butter Review 2026: Video Creative Suite Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Butter is an AI-powered video creative suite for marketing teams. See features, templates, pricing, pros, cons, and FAQs before you sign up.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Butter (usebutter.com, app.butter.video) is an AI-native video creative suite founded in 2020 and headquartered in Los Angeles, California, led by CEO and co-founder Nate Yu, who previously worked on growth teams at Shyp and Athos and on the early team at Grubwithus (Y Combinator W12, which pivoted into GOAT). The company operates as a small, lean team - reported at around 10 to 15 people as of 2025 - and was generating an estimated $1.5 million in annual revenue as of mid-2025, according to third-party revenue-tracking sources. Butter's product lets marketing and creative teams produce branded videos, social ads, and motion graphics faster than traditional tools like Adobe After Effects by starting from a library of remixable templates built by real brands, then customizing them with a modular block-based editor rather than a blank timeline. The platform's stated customer base includes major brands such as Disney, SpaceX, DoorDash, Sony Music, and Lyft, and it markets itself specifically to direct-to-consumer (DTC) and e-commerce brands that need a high volume of short-form video content for paid social and marketing campaigns. Key product capabilities include a template and building-block library that teams can remix and save into their own on-brand libraries, motion graphics and animation tools designed to be more approachable than professional compositing software, and a set of AI-assisted features: automatic background removal for product and model footage, one-click AI video captioning with customizable caption styling, and automatic resizing (magic resize) of a single video into multiple aspect ratios for different social platforms. Note: there is a separate, unrelated company also called Butter (based in Denmark, founded around the same time, known for its virtual workshop and meeting-facilitation software with breakout rooms and a speaker queue) - the two products share a common name and, confusingly, some overlapping historical domain infrastructure, but public founder records (Nate Yu for the video product versus Jakob Knutzen, Christopher Holm-Hansen, and Adam Wan for the workshop product) indicate they are distinct ventures; this entry describes the video creative suite. Butter's pricing includes a free tier for individual use and paid Pro plans reported by third-party review sites to start around $18 per month, with limits based on factors like AI auto-captioning minutes; the company does not publish a full public pricing breakdown by feature, and a 7-day money-back guarantee applies to paid subscriptions.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd85d55fa-0d1c-4513-9dd7-5d0afd3835fd';

