-- ── Bytebase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bytebase is an open-source database DevOps tool providing schema migration, SQL review, and GitOps-based change management for teams running multiple databases.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community, self-hosted); Pro $20/user/month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$~12 employees$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bytebase Review 2026: Open-Source Database DevOps Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Bytebase is an open-source database CI/CD and schema change tool. See pricing, features, self-hosting options, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bytebase is an open-source database DevOps and CI/CD platform founded in 2021 by co-founders Tianzhou Chen (CEO) and Danny Xu (CTO), former technical leads on Google Cloud SQL and Google's API infrastructure. The company is headquartered in Mountain View, California, and operates with a small team of roughly a dozen employees. Bytebase's source code is publicly available on GitHub under the bytebase/bytebase repository and the project is listed in the CNCF and Platform Engineering landscapes, positioning it as the 'GitHub/GitLab for database DevSecOps.' The tool addresses the database change management lifecycle - schema migrations, data changes, SQL review, version control of schema changes, and rollback - for teams that would otherwise coordinate these changes manually or through ad hoc scripts. Bytebase supports a broad set of database engines including PostgreSQL, MySQL, MariaDB, TiDB, Snowflake, ClickHouse, MongoDB, Redis, Oracle, SQL Server, and Google Cloud Spanner. Key capabilities include native GitHub/GitLab integration for a database-as-code (GitOps) workflow where schema changes are reviewed and merged like application code, automated schema migration with built-in rollback support, more than 200 configurable SQL lint rules for enforcing review standards, column-level data masking for protecting sensitive fields, and fine-grained role-based access control at the project and workspace level. Bytebase follows an open-core pricing model with three tiers. The Community edition is free forever and self-hosted, supporting up to 20 users and 10 database instances with community support and core database change management. The Pro plan costs $20 per user per month, is cloud-hosted (though self-hosting is also supported), removes the user cap, adds Google/GitHub SSO, user groups, and database groups, with email support. The Enterprise tier is custom-priced on an annual contract and adds advanced authentication (OIDC, LDAP, SCIM, 2FA), custom approval workflows, dynamic data masking, unlimited audit log retention, custom roles/branding, and optional add-ons like high availability and HIPAA BAA support, payable via credit card, wire transfer, or AWS/GCP Marketplace. Because it is open source and self-hostable at the Community tier, Bytebase is commonly adopted by engineering teams, DBAs, and platform engineering groups who want database schema change control (similar in spirit to Flyway or Liquibase, but with a web UI and governance workflow) without being locked into a single vendor's cloud.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4cb53b3b-4fcf-4555-b0b5-3f0bbbd4d8a4';

