-- ── Cabin ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cabin is a lightweight, privacy-first, cookieless web analytics tool that tracks visitors without cookies, IP storage, or fingerprinting.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; Pro $19/month$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Independent/solo project (1 person)$q$, company_size),
  headquarters = COALESCE($q$European Union$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cabin Analytics Review 2026: Pricing & Privacy Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Cabin is a privacy-first, cookieless Google Analytics alternative. See pricing, features, compliance details, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cabin (withcabin.com) is a lightweight, privacy-first web analytics tool positioned as a cookieless, carbon-conscious alternative to Google Analytics. The product was created by developer Nic Mulvaney and was originally incubated inside Normally, a digital product design studio, starting around 2020. When Normally closed in January 2025, Cabin became a fully independent product wholly owned and operated by Mulvaney, making it effectively a solo-run indie tool rather than a venture-backed company. Cabin's core technical differentiator is that its tracking script does not use cookies, does not store visitor IP addresses, and does not perform browser fingerprinting; instead it uses a method based on comparing a resource's last-modified time against the start of the day to estimate unique visits without persisting any personal identifiers. This design is intended to make Cabin compliant with GDPR, CCPA, ePrivacy, and PECR by default, meaning sites using Cabin generally do not need to show a cookie consent banner. All data is described as end-to-end encrypted and processed and stored exclusively within the EU, and the service states it runs on 100% renewable energy. In addition to standard analytics (page views, referrers, geographic and device breakdowns, custom events, UTM campaign tracking), Cabin includes a distinctive carbon-emissions reporting feature that estimates the CO2 footprint of a website's traffic over time and highlights oversized page assets contributing to that footprint. The company also publishes a public analytics API. Cabin's script is marketed as roughly 77 times smaller than Google Analytics' tracking script, which the company says collectively saves users terabytes of data transfer each month across its customer base. Pricing is simple and two-tiered: a free Basic plan covers one website with 30-day data retention, unlimited page views, data export, CO2 reporting, custom events, weekly email reports, and a custom subdomain for the public dashboard; the Pro plan is $19 per month and removes the website cap and retention limit, offering unlimited websites and unlimited data retention with the same feature set, subject to a fair-use policy. Cabin is aimed at privacy-conscious website owners, indie developers, and small businesses in the EU (or serving EU visitors) who want basic traffic analytics without a cookie banner or the compliance overhead of Google Analytics.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f0050715-8a0a-4437-8c80-e7d842301783';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'f0050715-8a0a-4437-8c80-e7d842301783' AND logo IS NULL AND website IS NOT NULL;

