-- ── cal ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$cal is the classic Unix command-line utility that prints a simple text calendar for a given month or year, built into virtually every Unix-like operating system.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$cal Command: Unix Calendar Utility Guide & Usage$q$, seo_title),
  seo_meta_description = COALESCE($q$cal is the built-in Unix/Linux/macOS command-line calendar tool. Learn its history, usage, options, and how it differs from ncal and gcal.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$cal is not a company or SaaS product but a small command-line utility for printing a text-based calendar, present in essentially every Unix and Unix-like operating system since the earliest days of Unix. The original version was written by Doug McIlroy (also known for inventing the Unix pipe) for the first PDP-11 implementation of Unix around 1971, and a cal command was present in Version 6 AT&T UNIX, making it one of the small set of utilities included in Ken Thompson's original Unix implementation. Because of this lineage, cal is specified in the Single UNIX Specification and ships by default on Linux distributions, macOS and other BSD-derived systems, Plan 9, and Inferno, typically as part of a base utilities package (on Linux, often bundled in packages like util-linux or bsdmainutils depending on distribution). With no arguments, cal prints a calendar for the current month to the terminal; it also accepts a month and year to print an arbitrary month, or a single year argument to print all twelve months of that year at once. Common options let users control whether the week starts on Sunday or Monday, display Julian (day-of-year) dates alongside calendar dates, and highlight the current day. A well-known quirk of cal, dating back to its earliest Unix versions, is its correct handling of the September 1752 calendar transition, when eleven days were dropped from the Julian-to-Gregorian calendar switch in Britain and its colonies - running 'cal 9 1752' on many implementations shows this historical gap. Because cal is a small, static utility rather than an evolving product, it has no company, no pricing, no roadmap, no accounts, and no version-specific feature tiers in the way a commercial SaaS tool would; different operating systems bundle slightly different implementations (for example, GNU coreutils/util-linux's cal on Linux versus BSD's cal on macOS), which can produce small differences in default output formatting or supported flags, but the core function - printing a calendar to a terminal - has remained consistent for more than five decades. Related and complementary tools include ncal (an alternate output format available on most systems) and gcal (a more feature-rich GNU calendar utility that is a separate, optional install). Because cal ships as a standard part of the operating system rather than being installed or purchased separately, it is best understood as a ubiquitous, zero-configuration utility for developers and system administrators who need a quick calendar reference inside a terminal session, rather than as a commercial product with a company behind it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cb305b30-042c-4afd-9644-7a70d5644c21';

